div.script:
(async function() {
  const base = 'https://cdn.jsdelivr.net/gh/smartfoloo/arsenic@main/';

  // 1. Manually fetch the Arsenic HTML
  // We use a cache-buster (?v=1) to try and slip past the 403
  try {
    const resp = await fetch(base + 'index.html?v=1');
    let html = await resp.text();

    // 2. Fix the links inside Arsenic so they point to jsDelivr
    // This replaces things like 'href="style.css"' with the full URL
    html = html.replace(/href="/g, `href="${base}`);
    html = html.replace(/src="/g, `src="${base}`);

    // 3. Inject it into the page
    document.body.innerHTML = html;

    // 4. Manually trigger the scripts
    const scripts = document.querySelectorAll('script');
    scripts.forEach(oldScript => {
      const newScript = document.createElement('script');
      Array.from(oldScript.attributes).forEach(attr => newScript.setAttribute(attr.name, attr.value));
      newScript.appendChild(document.createTextNode(oldScript.innerHTML));
      document.body.appendChild(newScript);
    });
  } catch (e) {
    // If fetch still fails, we use a redirect as a fallback
    window.location.replace(base + "index.html");
  }
})();
